#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int canGroup(int *hand, int handSize, int groupSize) {
    qsort(hand, handSize, sizeof(int), compare);
    int *vals = (int*)malloc(handSize * sizeof(int));
    int *cnt = (int*)malloc(handSize * sizeof(int));
    int m = 0;
    vals[0] = hand[0];
    cnt[0] = 1;
    m = 1;
    for (int i = 1; i < handSize; ++i) {
        if (hand[i] == vals[m-1]) {
            cnt[m-1]++;
        } else {
            vals[m] = hand[i];
            cnt[m] = 1;
            ++m;
        }
    }
    for (int i = 0; i < m; ++i) {
        while (cnt[i] >= groupSize) {
            for (int j = 0; j < groupSize; ++j) {
                if (i + j >= m || vals[i+j] != vals[i] + j) {
                    free(vals);
                    free(cnt);
                    return 0;
                }
                cnt[i+j]--;
            }
        }
    }
    for (int i = 0; i < m; ++i) {
        if (cnt[i] > 0) {
            free(vals);
            free(cnt);
            return 0;
        }
    }
    free(vals);
    free(cnt);
    return 1;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N, groupSize;
        scanf("%d %d", &N, &groupSize);
        int *hand = (int*)malloc(N * sizeof(int));
        for (int i = 0; i < N; ++i) scanf("%d", &hand[i]);
        if (N % groupSize != 0) {
            printf("NO\n");
        } else if (canGroup(hand, N, groupSize)) {
            printf("YES\n");
        } else {
            printf("NO\n");
        }
        free(hand);
    }
    return 0;
}

