#include <bits/stdc++.h>
using namespace std;

bool canGroup(vector<int>& hand, int groupSize) {
    sort(hand.begin(), hand.end());
    vector<int> vals;
    vector<int> cnt;
    for (int x : hand) {
        if (!vals.empty() && vals.back() == x) {
            ++cnt.back();
        } else {
            vals.push_back(x);
            cnt.push_back(1);
        }
    }
    int m = vals.size();
    for (int i = 0; i < m; ++i) {
        while (cnt[i] >= groupSize) {
            for (int j = 0; j < groupSize; ++j) {
                if (i + j >= m || vals[i + j] != vals[i] + j) return false;
                --cnt[i + j];
            }
        }
    }
    for (int c : cnt) if (c > 0) return false;
    return true;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; cin >> T;
    while (T--) {
        int N, groupSize; cin >> N >> groupSize;
        vector<int> hand(N);
        for (int &x : hand) cin >> x;
        if (N % groupSize != 0) {
            cout << "NO\n";
        } else if (canGroup(hand, groupSize)) {
            cout << "YES\n";
        } else {
            cout << "NO\n";
        }
    }
    return 0;
}

