import java.io.*;
import java.util.*;

public class Main {
    private static boolean canGroup(int[] hand, int groupSize) {
        Arrays.sort(hand);
        List<Integer> vals = new ArrayList<>();
        List<Integer> cnt = new ArrayList<>();
        for (int x : hand) {
            if (!vals.isEmpty() && vals.get(vals.size() - 1) == x) {
                cnt.set(cnt.size() - 1, cnt.get(cnt.size() - 1) + 1);
            } else {
                vals.add(x);
                cnt.add(1);
            }
        }
        int m = vals.size();
        for (int i = 0; i < m; ++i) {
            while (cnt.get(i) >= groupSize) {
                for (int j = 0; j < groupSize; ++j) {
                    if (i + j >= m || vals.get(i + j) != vals.get(i) + j) return false;
                    cnt.set(i + j, cnt.get(i + j) - 1);
                }
            }
        }
        for (int c : cnt) if (c > 0) return false;
        return true;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            st = new StringTokenizer(br.readLine());
            int N = Integer.parseInt(st.nextToken());
            int groupSize = Integer.parseInt(st.nextToken());
            int[] hand = new int[N];
            st = new StringTokenizer(br.readLine());
            for (int i = 0; i < N; ++i) hand[i] = Integer.parseInt(st.nextToken());
            if (N % groupSize != 0) {
                sb.append("NO\n");
            } else if (canGroup(hand, groupSize)) {
                sb.append("YES\n");
            } else {
                sb.append("NO\n");
            }
        }
        System.out.print(sb.toString());
    }
}

