import sys

def can_group(hand, groupSize):
    hand.sort()
    vals = []
    cnt = []
    for x in hand:
        if vals and vals[-1] == x:
            cnt[-1] += 1
        else:
            vals.append(x)
            cnt.append(1)
    m = len(vals)
    i = 0
    while i < m:
        while cnt[i] >= groupSize:
            for j in range(groupSize):
                if i + j >= m or vals[i + j] != vals[i] + j:
                    return False
                cnt[i + j] -= 1
        i += 1
    return all(c == 0 for c in cnt)

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        groupSize = int(next(it))
        hand = [int(next(it)) for _ in range(N)]
        if N % groupSize != 0:
            out_lines.append("NO")
        elif can_group(hand, groupSize):
            out_lines.append("YES")
        else:
            out_lines.append("NO")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    main()

